import{_ as a,o as e,c as i,a1 as o}from"./chunks/framework.BwbI10pK.js";const _=JSON.parse('{"title":"测试工程","description":"","frontmatter":{},"headers":[],"relativePath":"testing/index.md","filePath":"testing/index.md"}'),r={name:"testing/index.md"};function l(n,t,s,d,h,u){return e(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="测试工程" tabindex="-1">测试工程 <a class="header-anchor" href="#测试工程" aria-label="Permalink to &quot;测试工程&quot;">​</a></h1><blockquote><p>副标题：从负载测试、端到端测试到单元测试，构建可验证的质量保障体系</p></blockquote><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><p>测试不是开发完成后的&quot;收尾动作&quot;，而是一套贯穿需求、设计、交付全生命周期的工程方法。本模块把测试拆解为&quot;验证、隔离、回归&quot;三组目标：验证系统在真实压力下的边界，隔离缺陷到具体层次，回归保障每次变更不引入新问题。</p><p>每类测试都配套工具链选型、场景设计与结果分析方法，避免&quot;跑了测试但说不清结论&quot;的伪覆盖。</p><h2 id="核心主题" tabindex="-1">核心主题 <a class="header-anchor" href="#核心主题" aria-label="Permalink to &quot;核心主题&quot;">​</a></h2><ul><li><strong>负载与性能测试</strong>：测试计划、负载模型、JMeter 脚本参数化、TPS / 响应时间 / 错误率指标体系、瓶颈定位</li><li><strong>端到端测试</strong>：Playwright / Cypress 场景设计、断言策略、并行执行、稳定性治理</li><li><strong>单元与集成测试</strong>：Jest / Vitest 测试金字塔、Mock 策略、覆盖率边界、契约测试</li><li><strong>监控与可观测性</strong>：Grafana、APM、OCP 指标采集、95% 百分位响应时间分析</li><li><strong>稳定性保障</strong>：降级与熔断验证、容量规划、第三方依赖压力测试</li></ul><h2 id="文章导览" tabindex="-1">文章导览 <a class="header-anchor" href="#文章导览" aria-label="Permalink to &quot;文章导览&quot;">​</a></h2><ul><li><a href="/testing/load-testing-practice">负载测试工程实践：从测试计划到瓶颈定位的全流程方法论</a> — 负载测试全流程方法论与瓶颈诊断框架</li></ul><h2 id="适用读者" tabindex="-1">适用读者 <a class="header-anchor" href="#适用读者" aria-label="Permalink to &quot;适用读者&quot;">​</a></h2><ul><li>测试工程师与质量负责人，需要建立团队级的负载测试与瓶颈定位框架</li><li>中高级前端工程师，希望理解系统在真实压力下的行为边界</li><li>前端架构师，需要在技术选型时评估方案的扩展性与容错能力</li></ul>',11)])])}const p=a(r,[["render",l]]);export{_ as __pageData,p as default};
